package tkn20

// Backwards-compatibility (interop) test for the AND-share fix.
//
// The fix in (*Formula).share only changes how the KEM secret is shared at
// ENCRYPTION time; the ciphertext format and the decryption algorithm are
// unchanged, and both the old and new sharings are valid additive sharings that
// a satisfying set reconstructs. Therefore a ciphertext produced by the buggy
// (pre-fix) code must remain decryptable by the fixed code using a key that
// satisfies the policy.
//
// The vectors below were generated on the unfixed revision (becaf2f) via the
// public API:
//
//	pk, msk := Setup(rand.Reader)
//	policy.FromString("role: admin and dept: engineering")
//	ct := pk.Encrypt(rand.Reader, policy, plaintext)
//
// andShareMSKHex is msk.MarshalBinary(); andShareCTHex is the ciphertext.

import (
	"bytes"
	"crypto/rand"
	"encoding/hex"
	"testing"
)

const (
	andShareInteropPolicy    = "role: admin and dept: engineering"
	andShareInteropPlaintext = "backwards-compatibility test vector: buggy ciphertext"

	// Master secret key (SystemSecretKey.MarshalBinary), produced by the buggy revision.
	andShareMSKHex = ""

	// Ciphertext (PublicKey.Encrypt), produced by the buggy revision.
	andShareCTHex = ""
)

// TestAndShareInteropBuggyCiphertext decrypts a ciphertext produced by the
// pre-fix (buggy) encryptor using a freshly derived satisfying key on the
// current (fixed) code. It guards against a regression that would change the
// share layout in a format-incompatible way and break old ciphertexts.
func TestAndShareInteropBuggyCiphertext(t *testing.T) {
	mskBytes, err := hex.DecodeString(andShareMSKHex)
	if err != nil {
		t.Fatalf("decoding MSK vector: %s", err)
	}
	ct, err := hex.DecodeString(andShareCTHex)
	if err != nil {
		t.Fatalf("decoding ciphertext vector: %s", err)
	}

	msk := SystemSecretKey{}
	if err = msk.UnmarshalBinary(mskBytes); err != nil {
		t.Fatalf("unmarshalling MSK vector: %s", err)
	}

	// Derive a fresh key for an attribute set that satisfies the policy.
	attrs := Attributes{}
	attrs.FromMap(map[string]string{"role": "admin", "dept": "engineering"})
	sk, err := msk.KeyGen(rand.Reader, attrs)
	if err != nil {
		t.Fatalf("KeyGen: %s", err)
	}

	pt, err := sk.Decrypt(ct)
	if err != nil {
		t.Fatalf("fixed code failed to decrypt a buggy-produced ciphertext: %s", err)
	}
	if !bytes.Equal(pt, []byte(andShareInteropPlaintext)) {
		t.Fatalf("plaintext mismatch: got %q want %q", pt, andShareInteropPlaintext)
	}

	// A non-satisfying key must still be refused on the fixed code.
	bad := Attributes{}
	bad.FromMap(map[string]string{"role": "guest"})
	badKey, err := msk.KeyGen(rand.Reader, bad)
	if err != nil {
		t.Fatalf("KeyGen(bad): %s", err)
	}
	if _, err := badKey.Decrypt(ct); err == nil {
		t.Fatalf("non-satisfying key unexpectedly decrypted the buggy ciphertext")
	}
}
